// TOKEN DE TU BOT
const TOKEN = '8524499239:AAEgU7QiBZMwJ1YPErkHVGJ23CT5IzWUMGw';

// Obtener último mensaje procesado
if (!$workflow.staticData.offset) {
  $workflow.staticData.offset = 0;
}

try {
  // Pedir actualizaciones a Telegram
  const response = await fetch(
    `https://api.telegram.org/bot${TOKEN}/getUpdates?offset=${$workflow.staticData.offset}&timeout=5`,
    { method: 'GET' }
  );

  const data = await response.json();

  // Si no hay mensajes, terminar
  if (!data.result || data.result.length === 0) {
    return [];
  }

  // Procesar cada mensaje
  const mensajes = [];

  for (const update of data.result) {
    // Actualizar offset para no procesar el mismo mensaje dos veces
    $workflow.staticData.offset = update.update_id + 1;

    // Solo procesar si tiene mensaje de texto
    if (update.message && update.message.text) {
      mensajes.push({
        json: {
          chat_id: update.message.chat.id,
          texto: update.message.text,
          usuario: update.message.from.first_name || 'Usuario',
          token: TOKEN
        }
      });
    }
  }

  return mensajes;

} catch (error) {
  console.error('Error obteniendo mensajes:', error);
  return [];
}

